func newListingsPromotedCmd(flags *rootFlags) *cobra.Command {
	var flagNkw string
	var flagLHAuction string
	var flagLHBIN string
	var flagSacat string
	var flagUdlo string
	var flagUdhi string
	var flagSop string
	var flagIpg string
	var flagLHItemCondition string

	cmd := &cobra.Command{
		Use:         "listings",
		Short:       "Search active eBay listings by keyword",
		Long:        "Shortcut for 'listings list'. Search active eBay listings by keyword",
		Example:     "  ebay-pp-cli listings",
		Annotations: map[string]string{"pp:endpoint": "listings.list"},
		RunE: func(cmd *cobra.Command, args []string) error {
			if !cmd.Flags().Changed("nkw") && !flags.dryRun {
				return fmt.Errorf("required flag \"%s\" not set", "nkw")
			}
			c, err := flags.newClient()
			if err != nil {
				return err
			}

			perPage := 60
			if flagIpg != "" {
				if n, err := strconv.Atoi(flagIpg); err == nil && n > 0 {
					perPage = n
				}
			}
			var minPrice, maxPrice float64
			if flagUdlo != "" {
				minPrice, _ = strconv.ParseFloat(flagUdlo, 64)
			}
			if flagUdhi != "" {
				maxPrice, _ = strconv.ParseFloat(flagUdhi, 64)
			}
			items, err := srcebay.New(c).FetchActive(context.Background(), srcebay.SearchOptions{
				Query:    flagNkw,
				Auction:  flagLHAuction == "1",
				BIN:      flagLHBIN == "1",
				Category: flagSacat,
				MinPrice: minPrice,
				MaxPrice: maxPrice,
				PerPage:  perPage,
				Sort:     "newest",
			})
			if err != nil {
				return classifyAPIError(err)
			}
			if items == nil {
				items = []srcebay.Listing{}
			}
			data, err := json.Marshal(items)
			if err != nil {
				return err
			}
			prov := DataProvenance{Source: "live", ResourceType: "listings"}

			printProvenance(cmd, len(items), prov)

			if flags.csv {
				return printOutputWithFlags(cmd.OutOrStdout(), data, flags)
			}
			if flags.asJSON || !isTerminal(cmd.OutOrStdout()) {
				filtered := data
				if flags.selectFields != "" {
					filtered = filterFields(filtered, flags.selectFields)
				} else if flags.compact {
					filtered = compactFields(filtered)
				}
				wrapped, wrapErr := wrapWithProvenance(filtered, prov)
				if wrapErr != nil {
					return wrapErr
				}
				return printOutput(cmd.OutOrStdout(), wrapped, true)
			}
			if wantsHumanTable(cmd.OutOrStdout(), flags) {
				var rows []map[string]any
				if json.Unmarshal(data, &rows) == nil && len(rows) > 0 {
					if err := printAutoTable(cmd.OutOrStdout(), rows); err != nil {
						return err
					}
					if len(rows) >= 25 {
						fmt.Fprintf(os.Stderr, "\nShowing %d results. To narrow: add --limit, --json --select, or filter flags.\n", len(rows))
					}
					return nil
				}
			}
			return printOutputWithFlags(cmd.OutOrStdout(), data, flags)
		},
	}
	cmd.Flags().StringVar(&flagNkw, "nkw", "", "Keyword query")
	cmd.Flags().StringVar(&flagLHAuction, "lh-auction", "", "1 to filter to auctions only")
	cmd.Flags().StringVar(&flagLHBIN, "lh-bin", "", "1 to filter to Buy It Now only")
	cmd.Flags().StringVar(&flagSacat, "sacat", "", "Category id filter")
	cmd.Flags().StringVar(&flagUdlo, "udlo", "", "Minimum price")
	cmd.Flags().StringVar(&flagUdhi, "udhi", "", "Maximum price")
	cmd.Flags().StringVar(&flagSop, "sop", "", "Sort: 1 ending-soonest, 10 newly-listed, 12 newest, 13 ending-latest")
	cmd.Flags().StringVar(&flagIpg, "ipg", "", "Items per page (max 240)")
	cmd.Flags().StringVar(&flagLHItemCondition, "lh-item-condition", "", "Condition filter codes (1000=new, 3000=used, 2000=refurb, 5000=for-parts)")

	// Wire sibling endpoints and sub-resources as subcommands

	return cmd
}
